import { Center } from '@chakra-ui/react';
import { IOption } from '@constants';
import { Address } from '@domain/address';
import {
  DonorProfileResponse as DonorProfile,
  useGetDonorProfile,
} from '@state/user/donor_profile/queries/useGetDonorProfile';
import { Form } from '@ui/components/formControls/Form';
import { Loading } from '@ui/components/Loading';
import { toTitleCase } from '@utils';
import { isValidEmail } from '@utils/validations/validations';
import { isValidPhoneNumber } from 'libphonenumber-js';
import { ReactNode, useCallback, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import * as yup from 'yup';
import { ContactInformationInnerForm } from './ContactInformationInnerForm';

type Props = {
  footer?: ReactNode;
  onSubmit: (
    values: DonorProfile & { employerAddress: Address; isCurrentlyEmployed: boolean }
  ) => void;
  showContact?: boolean;
  showName?: boolean;
};

export const ContactInformationForm = ({ footer, onSubmit, showContact, showName }: Props) => {
  const { t } = useTranslation('donors', { keyPrefix: 'donorForms.contactInformation' });
  const { t: tValidation } = useTranslation('actionPagesBuilder', {
    keyPrefix: 'public.validation',
  });

  const { t: tCommon } = useTranslation('common');
  const { data: donorProfile, isLoading } = useGetDonorProfile();

  const occupationOptions = useMemo<IOption[]>(
    () =>
      t('occupationOptions', { returnObjects: true }).map((option) => ({
        label: toTitleCase(option),
        value: option,
      })),
    [t]
  );

  const onSubmitForm = useCallback((values) => onSubmit(values), [onSubmit]);

  const schema: yup.Schema = yup.object().shape({
    country: yup
      .string()
      .test('phone_country', tValidation('sameCountry'), (country, { parent }) => {
        if (country !== parent.phoneCountry) {
          return false;
        }

        return true;
      }),
    email: yup
