import { useGetAccount } from '@state/accounts';
import { generateQueryKey, resourceKeys } from '@state/cacheHelper';
import { makeSearchParams } from '@utils';
import { useQuery } from 'react-query';

export const useGetAccountConfiguration = (
  accountId?: string
): {
  accountConfiguration?: AccountConfiguration;
  isLoading: boolean;
} => {
  const { currentAccount } = useGetAccount();
  const normalizedAccountId = accountId || currentAccount?.id;
  const params = makeSearchParams({
    accountId: normalizedAccountId,
  });

  const query = useQuery<AccountConfiguration, IErrorResponse>(
    generateQueryKey({
      accountId: normalizedAccountId,
      resourceKey: resourceKeys.accountConfiguration,
    }),
    async () => {
      return new ApiClient().get<AccountConfiguration>(
        `/account_configuration?${params.toString()}`
      );
    },
    {
      enabled: !!normalizedAccountId,
      keepPreviousData: true,
    }
  );

  return {
    accountConfiguration: query.data,
    isLoading: query.isLoading,
  };
};

